# WRONG — full transcript embedded in the Kafka record (may exceed 1 MB)
await producer.send("agent.events", value={
    "type": "run.finished",
    "full_transcript": very_large_string,   # ← dangerous
})

# CORRECT — store the large object elsewhere, publish a pointer
s3_key = await upload_to_s3(very_large_string)
await producer.send("agent.events", value={
    "type": "run.finished",
    "transcript_s3_key": s3_key,           # ← tiny pointer
})
